SELECT company_id, name
FROM companies
WHERE is_supplier = 1 AND customer_type = 'company';

SELECT (
    SELECT COUNT(*)
    FROM companies
    WHERE customer_type = 'individual'
) AS lone_wolves,
(
    SELECT COUNT(*)
    FROM companies
    WHERE is_supplier = 1
) AS shepherds;

SELECT DISTINCT interaction_type 
FROM interactions 
WHERE interaction_date < '2023-01-01';
